+fn select_hard_regime_plan(n_rows: usize, n_cols: usize, a: &[Gf256]) -> HardRegimePlan {
+    let total_cells = n_rows.saturating_mul(n_cols);
+    if n_cols < BLOCK_SCHUR_MIN_COLS || total_cells == 0 {
+        return HardRegimePlan::Markowitz;
+    }
